mapper.select:
SELECT EXISTS (
    SELECT 1
    FROM register r
    WHERE r.id = #{registerId}
      AND (
          r.patient_id IN

              #{pid}

          OR EXISTS (
              SELECT 1
              FROM patient p
              WHERE p.id IN

                  #{pid}

                AND p.delmark = 0
                AND p.real_name = r.real_name
                AND p.birthdate = r.birthdate
          )
      )
)
